const notas: number[] = [8.5, 7.0, 9.2, 6.8];
console.log(notas);
console.log(`Total de provas: ${notas.length}`);
// [8.5, 7.0, 9.2, 6.8]
// Total de provas: 4

// Array vazio — começa sem itens
const listaDeTarefas: string[] = [];
console.log(listaDeTarefas.length);
// 0 — vazio, mas pronto para receber itens

// Array de booleanos — checklist
const tarefasConcluidas: boolean[] = [true, true, false, true];
console.log(tarefasConcluidas);
console.log(tarefasConcluidas.length);
// [true, true, false, true]
// 4

// Comparando: SEM array vs COM array
// Sem array — 4 variáveis separadas:
const dia1: number = 28;
const dia2: number = 31;
const dia3: number = 25;
const dia4: number = 29;

// Com array — 1 variável organizada:
const temperaturas: number[] = [28, 31, 25, 29];
console.log(temperaturas);
// [28, 31, 25, 29]

// O tipo restringe o que pode entrar
const cidades: string[] = ["Curitiba", "Recife", "Salvador"];
console.log(cidades);
// ["Curitiba", "Recife", "Salvador"]

// cidades.push(42); // ERRO do TypeScript!
// string[] só aceita strings, não números

// Acessando notas por posição
const notas: number[] = [8.5, 7.0, 9.2, 6.8];

console.log(notas[0]);
console.log(notas[2]);
console.log(notas[3]);
// 8.5 (primeira)
// 9.2 (terceira)
// 6.8 (quarta e última)

// Acessando o último item — fórmula universal
const cidades: string[] = ["Curitiba", "Recife", "Salvador"];

const ultima: string = cidades[cidades.length - 1];
console.log(ultima);
// Salvador (posição 2, que é 3 - 1)

// Posição que não existe → undefined
const cores: string[] = ["azul", "verde", "vermelho"];

console.log(cores[10]);
// undefined — não existe posição 10

// Modificando um item existente
const temperaturas: number[] = [22, 25, 19];
console.log(temperaturas[0]);

temperaturas[0] = 24;
console.log(temperaturas[0]);
// 22
// 24 — o primeiro item foi substituído

// Usando índice em template literal
const dias: string[] = ["Seg", "Ter", "Qua", "Qui", "Sex"];

console.log(`Primeiro dia útil: ${dias[0]}`);
console.log(`Último dia útil: ${dias[dias.length - 1]}`);
// Primeiro dia útil: Seg
// Último dia útil: Sex

// A contagem sempre começa em 0
const meses: string[] = ["Jan", "Fev", "Mar", "Abr"];

// Posição 0 → Jan (primeiro)
// Posição 1 → Fev (segundo)
// Posição 2 → Mar (terceiro)
// Posição 3 → Abr (quarto)
console.log(meses[0]);
console.log(meses[3]);
// Jan
// Abr

// Lista de compras — adicionando itens
const compras: string[] = ["arroz", "feijão"];

compras.push("macarrão");
compras.push("leite");

console.log(compras);
// ["arroz", "feijão", "macarrão", "leite"]

// Removendo o último item com pop
const fila: string[] = ["Ana", "Bruno", "Clara"];

const saiu: string | undefined = fila.pop();

console.log(saiu);
console.log(fila);
// Clara (removida do final)
// ["Ana", "Bruno"]

// Atendendo o primeiro da fila com shift
const espera: string[] = ["Ana", "Bruno", "Clara"];

const atendido: string | undefined = espera.shift();

console.log(`Atendido: ${atendido}`);
console.log(espera);
// Atendido: Ana
// ["Bruno", "Clara"]

// Adicionando ao início com unshift
const tarefas: string[] = ["Estudar", "Almoçar"];

tarefas.unshift("Tomar café");

console.log(tarefas);
// ["Tomar café", "Estudar", "Almoçar"]

// push + pop: pilha de pratos
const pilha: string[] = [];

pilha.push("prato 1");
pilha.push("prato 2");
pilha.push("prato 3");
console.log(pilha);
// ["prato 1", "prato 2", "prato 3"]

pilha.pop();
console.log(pilha);
// ["prato 1", "prato 2"]

// Resumo dos 4 métodos
const lista: number[] = [10, 20, 30];

lista.push(40);
console.log(lista);
// [10, 20, 30, 40] — adicionou no final

lista.pop();
console.log(lista);
// [10, 20, 30] — removeu do final

lista.unshift(5);
console.log(lista);
// [5, 10, 20, 30] — adicionou no início

lista.shift();
console.log(lista);
// [10, 20, 30] — removeu do início

// for...of — percorrendo valores diretamente
const materias: string[] = ["Matemática", "Português", "Ciências"];

for (const materia of materias) {
  console.log(`Estudar: ${materia}`);
}
// Estudar: Matemática
// Estudar: Português
// Estudar: Ciências

// for clássico — quando precisa do índice
const classificacao: string[] = ["Ana", "Bruno", "Clara"];

for (let i: number = 0; i < classificacao.length; i++) {
  console.log(`${i + 1}° lugar: ${classificacao[i]}`);
}
// 1° lugar: Ana
// 2° lugar: Bruno
// 3° lugar: Clara

// Somando todos os valores com for...of
const precos: number[] = [15, 8, 22, 5];
let total: number = 0;

for (const preco of precos) {
  total = total + preco;
}

console.log(`Total: R$${total}`);
// Total: R$50

// Contando quantos itens atendem uma condição
const notas: number[] = [8, 5, 9, 3, 7, 6];
let aprovados: number = 0;

for (const nota of notas) {
  if (nota >= 6) {
    aprovados++;
  }
}

console.log(`Aprovados: ${aprovados}`);
// Aprovados: 4

// for clássico — acessando o próximo item
const temperaturas: number[] = [22, 25, 19, 28, 24];

for (let i: number = 0; i < temperaturas.length - 1; i++) {
  const diff: number = temperaturas[i + 1] - temperaturas[i];
  console.log(`Dia ${i + 1} → ${i + 2}: ${diff > 0 ? "+" : ""}${diff}°`);
}
// Dia 1 → 2: +3°
// Dia 2 → 3: -6°
// Dia 3 → 4: +9°
// Dia 4 → 5: -4°

// Percorrendo e montando uma string
const ingredientes: string[] = ["farinha", "ovos", "leite", "açúcar"];
let receita: string = "Ingredientes: ";

for (const item of ingredientes) {
  receita = receita + item + ", ";
}

console.log(receita);
// Ingredientes: farinha, ovos, leite, açúcar,

// map: transformando notas em conceitos
const notas: number[] = [8, 5, 9, 3, 7];

const conceitos: string[] = notas.map((n: number): string => {
  if (n >= 7) return "A";
  if (n >= 5) return "B";
  return "C";
});

console.log(conceitos);
// ["A", "B", "A", "C", "A"]

// map: formatando preços
const valores: number[] = [10, 25, 8, 42];

const formatados: string[] = valores.map(
  (v: number): string => `R$${v},00`
);

console.log(formatados);
// ["R$10,00", "R$25,00", "R$8,00", "R$42,00"]

// filter: selecionando notas de aprovação
const todasNotas: number[] = [8, 3, 9, 5, 7, 2, 6];

const aprovados: number[] = todasNotas.filter(
  (n: number): boolean => n >= 6
);

console.log(aprovados);
// [8, 9, 7, 6]

// filter: palavras com mais de 4 letras
const palavras: string[] = ["sol", "estrela", "lua", "cometa", "ar"];

const longas: string[] = palavras.filter(
  (p: string): boolean => p.length > 4
);

console.log(longas);
// ["estrela", "cometa"]

// Encadeando: filtrar pares e dobrar
const numeros: number[] = [1, 2, 3, 4, 5, 6];

const resultado: number[] = numeros
  .filter((n: number): boolean => n % 2 === 0)
  .map((n: number): number => n * 2);

console.log(resultado);
// [4, 8, 12] — pegou 2,4,6 e dobrou cada

// O original NUNCA muda
const original: number[] = [10, 20, 30];

const dobrado: number[] = original.map((n: number): number => n * 2);
const filtrado: number[] = original.filter((n: number): boolean => n > 15);

console.log(original);
console.log(dobrado);
console.log(filtrado);
// [10, 20, 30] — intacto!
// [20, 40, 60]
// [20, 30]

// push: adicionando ao final
const lista: string[] = ["item A", "item B"];
lista.push("item C");
console.log(lista);
// ["item A", "item B", "item C"]

// shift: removendo o primeiro
const fila: string[] = ["primeiro", "segundo", "terceiro"];
fila.shift();
console.log(fila);
// ["segundo", "terceiro"]

// for...of com formatação
const itens: string[] = ["Arroz", "Feijão", "Macarrão"];

for (const item of itens) {
  console.log(`- ${item}`);
}
// - Arroz
// - Feijão
// - Macarrão

// Erro: usando pop em vez de shift
const errado: string[] = ["A", "B", "C"];
errado.push("D");
errado.pop();
console.log(errado);
// ["A", "B", "C"] — pop removeu o "D" que acabou de entrar!
// shift removeria o "A" (primeiro), que é o desejado

// Simulando a sequência completa
const demo: string[] = ["Tarefa 1", "Tarefa 2", "Tarefa 3"];
console.log("Início:", demo);

demo.push("Tarefa 4");
console.log("Após push:", demo);

demo.shift();
console.log("Após shift:", demo);
// Início: ["Tarefa 1", "Tarefa 2", "Tarefa 3"]
// Após push: ["Tarefa 1", "Tarefa 2", "Tarefa 3", "Tarefa 4"]
// Após shift: ["Tarefa 2", "Tarefa 3", "Tarefa 4"]

// const protege a variável, não o conteúdo
const frutas: string[] = ["maçã", "banana"];
frutas.push("uva");
console.log(frutas);
// ["maçã", "banana", "uva"] — modificou o conteúdo, ok!

