// Encontrando a maior nota de uma turma
function maiorNota(notas: number[]): number {
  let maior: number = notas[0];
  for (const nota of notas) {
    if (nota > maior) {
      maior = nota;
    }
  }
  return maior;
}

console.log(maiorNota([7, 9, 5, 8]));
// 9

// Erro: inicializando com 0 (falha com negativos)
function maiorErrado(nums: number[]): number {
  let maior: number = 0;
  for (const n of nums) {
    if (n > maior) maior = n;
  }
  return maior;
}

console.log(maiorErrado([-5, -2, -8]));
// 0 ← ERRADO! -2 é o maior, mas 0 > -2

// Versão correta: inicializando com numeros[0]
function maiorCerto(nums: number[]): number {
  let maior: number = nums[0];
  for (const n of nums) {
    if (n > maior) maior = n;
  }
  return maior;
}

console.log(maiorCerto([-5, -2, -8]));
// -2 ← CORRETO!

// Mesmo padrão: encontrar o MENOR
function encontrarMenor(nums: number[]): number {
  let menor: number = nums[0];
  for (const n of nums) {
    if (n < menor) {
      menor = n;
    }
  }
  return menor;
}

console.log(encontrarMenor([3, 7, 2, 9, 4]));
// 2

// Passo a passo com [3, 7, 2, 9, 4]
// maior começa em 3 (primeiro item)
// 3 > 3? Não → maior = 3
// 7 > 3? Sim → maior = 7
// 2 > 7? Não → maior = 7
// 9 > 7? Sim → maior = 9
// 4 > 9? Não → maior = 9
// Resultado: 9

let maior: number = 3;
console.log(`Resultado: ${maior}`);  // simulação simplificada
maior = 7;
maior = 9;
console.log(`Final: ${maior}`);
// Resultado: 3
// Final: 9

// Array com um único elemento
function encontrarMaior(nums: number[]): number {
  let maior: number = nums[0];
  for (const n of nums) {
    if (n > maior) maior = n;
  }
  return maior;
}

console.log(encontrarMaior([100]));
// 100 — o único elemento é automaticamente o maior

// Índice 0: o primeiro elemento
const letras: string[] = ["A", "B", "C", "D"];

console.log(letras[0]);
console.log(letras[1]);
console.log(letras[3]);
// A (primeiro, posição 0)
// B (segundo, posição 1)
// D (quarto, posição 3)

// push: sempre adiciona ao final
const nums: number[] = [10, 20];

nums.push(30);
console.log(nums);
// [10, 20, 30] — o 30 foi para o final

nums.push(40);
console.log(nums);
// [10, 20, 30, 40]

// map: transforma cada item, mesmo tamanho
const precos: number[] = [5, 10, 15];

const comDesconto: number[] = precos.map(
  (p: number): number => p * 0.9
);

console.log(comDesconto);
// [4.5, 9, 13.5] — cada preço com 10% de desconto

// filter: seleciona, tamanho pode diminuir
const idades: number[] = [10, 18, 14, 21, 16];

const maiores: number[] = idades.filter(
  (i: number): boolean => i >= 18
);

console.log(maiores);
// [18, 21] — só os maiores de idade

// map vs filter: resultados diferentes
const valores: number[] = [1, 2, 3, 4, 5];

const mapeado: number[] = valores.map((n: number): number => n * 2);
const filtrado: number[] = valores.filter((n: number): boolean => n > 3);

console.log(mapeado);
console.log(filtrado);
// [2, 4, 6, 8, 10] — map: mesmo tamanho, valores transformados
// [4, 5] — filter: tamanho menor, valores originais mantidos

// Revisão: todos os conceitos juntos
const notas: number[] = [8, 5, 9, 3, 7];

console.log(notas[0]);
// 8 (índice 0 = primeiro)

notas.push(6);
console.log(notas);
// [8, 5, 9, 3, 7, 6] (push = final)

const altas: number[] = notas.filter((n: number): boolean => n >= 7);
console.log(altas);
// [8, 9, 7] (filter = seleciona)

const dobradas: number[] = altas.map((n: number): number => n * 2);
console.log(dobradas);
// [16, 18, 14] (map = transforma)
